import quoteSettingsService from '../services/quoteSettingsService';
export default {
  name: 'ConfigDevis',
  data() {
    return {
      settings: {
        validity_hours: 48
      },
      loading: true,
      error: null,
      saveMessage: null
    };
  },
  async mounted() {
    await this.loadSettings();
  },
  methods: {
    async loadSettings() {
      try {
        this.loading = true;
        this.error = null;
        this.settings = await quoteSettingsService.get();
      } catch (err) {
        this.error = 'Erreur lors du chargement des paramètres: ' + err.message;
        console.error(err);
      } finally {
        this.loading = false;
      }
    },
    async saveSettings() {
      if (!this.settings.id || !this.settings.validity_hours || this.settings.validity_hours < 1) {
        return;
      }
      try {
        await quoteSettingsService.update(this.settings.id, {
          validity_hours: this.settings.validity_hours
        });
        this.showSaveMessage('Paramètres enregistrés avec succès');
      } catch (err) {
        this.error = 'Erreur lors de la sauvegarde: ' + err.message;
        console.error(err);
      }
    },
    showSaveMessage(message) {
      this.saveMessage = message;
      setTimeout(() => {
        this.saveMessage = null;
      }, 3000);
    }
  }
};
